window.RF = {
  scenario(name){ return window.RF_DATA.scenarios[name] || null; },
  summary(name){ return window.RF_SUMMARY[name] || null; },
  list(){ return Object.keys(window.RF_DATA.scenarios); },
  symbol(name){ var s=this.scenario(name); return s?s.symbol:'$'; },
  fmt(n){ return n>=1e7?(n/1e7).toFixed(2)+'Cr':n>=1e6?(n/1e6).toFixed(2)+'M':n>=1e3?(n/1e3).toFixed(0)+'K':String(n); },
  /* read ?scenario= from URL, fall back to first */
  current(){
    var p=new URLSearchParams(location.search).get('scenario');
    if(p && window.RF_DATA.scenarios[p]) return p;
    return this.list()[0];
  },
  /* org helpers (uses resolved manager chain) */
  reports(name, mgrName){ var s=this.scenario(name); return s?s.employees.filter(e=>e.manager===mgrName):[]; },
  byPlacement(name, p){ var s=this.scenario(name); return s?s.employees.filter(e=>e.placement===p):[]; }
};

